def filter_open_tasks(tasks_data):
    """Filter to only open tasks (exclude closed/completed)."""
    closed_statuses = ['closed', 'completed']
    tasks = tasks_data.get('results', [])
    return [t for t in tasks if t.get('status', '').lower() not in closed_statuses]

def main():
    tasks_data = json.loads(TASKS_JSON)
    open_tasks = filter_open_tasks(tasks_data)
    
    print(f"Found {len(open_tasks)} open tasks:")
    for task in open_tasks:
        print(f"  - {task['id']}: {task['name']} (status: {task['status']})")
    
    # Output task IDs as JSON for easy processing
    task_ids = [t['id'] for t in open_tasks]
    print(json.dumps(task_ids))

if __name__ == "__main__":
    main()
